parameters.jsCode:
try {
  const email = $input.first().json;

  if (!email) {
    throw new Error("No email data received");
  }

  const subject = email.subject || "Meeting";
  let body = email.body || email.bodyText || email.snippet || "";

  // Decode HTML entities
  body = body.replace(/&#39;/g, "'").replace(/&quot;/g, '"').replace(/&amp;/g, '&');

  const fromEmail = email.from?.email || "organizer@company.com";
  const toField = email.to || "";

  // Detect source
  const isFathom = fromEmail.includes("fathom");
  const isFireflies = fromEmail.includes("fireflies");

  let attendeeEmails = [];
  let meetingTitle = subject;

  // EMAIL REGEX
  const emailRegex = /([a-zA-Z0-9._-]+@[a-zA-Z0-9._-]+\.[a-zA-Z0-9_-]+)/g;

  if (isFathom) {
    // FATHOM: Subject looks like "Recap of your meeting with priyanjanamuk09@gmail.com"

    // METHOD 1: Extract email directly from subject (MOST IMPORTANT)
    const subjectEmails = subject.match(emailRegex) || [];
    attendeeEmails.push(...subjectEmails);

    // METHOD 2: Also check body for emails
    const bodyEmails = body.match(emailRegex) || [];
    attendeeEmails.push(...bodyEmails);

    meetingTitle = subject.replace(/Recap of your meeting with\s*/i, "").trim();
  } else if (isFireflies) {
    // FIREFLIES: Extract from To field
    const toEmails = toField.match(emailRegex) || [];
    attendeeEmails.push(...toEmails);

    const bodyEmails = body.match(emailRegex) || [];
    attendeeEmails.push(...bodyEmails);

    meetingTitle = subject.replace(/Your meeting recap\s*-\s*/i, "").trim();
  } else {
    // FALLBACK: Extract from everything
    const allEmails = (subject + " " + body + " " + toField).match(emailRegex) || [];
    attendeeEmails.push(...allEmails);
  }

  // Remove duplicates
  attendeeEmails = [...new Set(attendeeEmails.map(e => e.toLowerCase()))];

  // Remove organizer email
  const organizerEmail = "priyanjana.codeit@gmail.com".toLowerCase();
  attendeeEmails = attendeeEmails.filter(e => e !== organizerEmail);

  // Parse meeting details
  const purposeMatch = body.match(/Meeting Purpose\s*([^\n]+)/i);
  const meetingPurpose = purposeMatch ? purposeMatch[1].trim() : "Team meeting";

  const takeawaysStart = body.toLowerCase().indexOf("key takeaways");
  let keyTakeaways = "See full meeting notes";
  if (takeawaysStart !== -1) {
    const section = body.substring(takeawaysStart, takeawaysStart + 400);
    const extracted = section.split('\n').slice(1, 5).filter(l => l.trim()).join(' ').trim();
    keyTakeaways = extracted || "See full meeting notes";
  }

  const actionStart = body.toLowerCase().indexOf("action items");
  let actionItems = "Review meeting notes";
  if (actionStart !== -1) {
    const section = body.substring(actionStart, actionStart + 300);
    const extracted = section.split('\n').slice(1, 3).filter(l => l.trim() && !l.includes("No action")).join(' ').trim();
    actionItems = extracted || "Review meeting notes";
  }

  const nextStart = body.toLowerCase().indexOf("next steps");
  let nextSteps = "Follow up on action items";
  if (nextStart !== -1) {
    const section = body.substring(nextStart, nextStart + 400);
    const extracted = section.split('\n').slice(1, 4).filter(l => l.trim()).join(' ').trim();
    nextSteps = extracted || "Follow up on action items";
  }

  return {
    json: {
      meetingTitle: meetingTitle || "Meeting",
      meetingPurpose: meetingPurpose,
      keyTakeaways: keyTakeaways,
      actionItems: actionItems,
      nextSteps: nextSteps,
      attendeeEmails: attendeeEmails.length > 0 ? attendeeEmails : [],
      organizerName: "Altix Codeit",
      organizerEmail: "priyanjana.codeit@gmail.com",
      companyName: "Codeit",
      fullEmailBody: body,
      emailSubject: subject,
      source: isFathom ? "Fathom" : isFireflies ? "Fireflies" : "Unknown",
    }
  };

} catch (error) {
  return {
    json: {
      error: error.message,
      meetingTitle: "Error",
      attendeeEmails: [],
      organizerName: "Altix Codeit",
      organizerEmail: "priyanjana.codeit@gmail.com",
      companyName: "Codeit",
    }
  };
}

