parameters.jsCode:
try {
  const calendarNode = $input.first().json;
  const fathomData = $node["Code in JavaScript"]?.json || {};

  let attendees = [];

  // Extract attendees from Calendar
  if (calendarNode?.items && calendarNode.items.length > 0 && calendarNode.items[0]?.attendees) {
    attendees = calendarNode.items[0].attendees;
  }

  // If no attendees, return default
  if (!attendees || attendees.length === 0) {
    return [{
      json: {
        attendeeName: "Participant",
        attendeeEmail: "priyanjana2019@gmail.com",
        attendeeRole: "Team Member",
        attended: false,
        mentionedInMeeting: false,
        calendarStatus: "unknown",
        meetingTitle: fathomData.meetingTitle || "Meeting",
        meetingPurpose: fathomData.meetingPurpose || "Team discussion",
        keyTakeaways: fathomData.keyTakeaways || "See full meeting notes",
        actionItems: fathomData.actionItems || "Review meeting notes",
        nextSteps: fathomData.nextSteps || "Follow up on action items",
        organizerName: fathomData.organizerName || "Altix Codeit",
        organizerEmail: fathomData.organizerEmail || "priyanjana.codeit@gmail.com",
        companyName: fathomData.companyName || "Codeit",
        debugInfo: "No attendees found in calendar"
      }
    }];
  }

  const items = [];
  const organizerEmail = fathomData.organizerEmail?.toLowerCase() || "priyanjana.codeit@gmail.com".toLowerCase();
  const bodyLower = fathomData.fullEmailBody?.toLowerCase() || "";

  // Process each attendee
  for (let i = 0; i < attendees.length; i++) {
    const attendee = attendees[i];

    // Skip if no email
    if (!attendee?.email) continue;

    // Skip organizer
    if (attendee.email.toLowerCase() === organizerEmail) continue;

    const email = attendee.email;
    const name = email.split('@')[0].replace(/[._-]/g, ' ').trim();
    const displayName = name.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');

    const mentioned = bodyLower.includes(name.toLowerCase()) || bodyLower.includes(email.toLowerCase());
    const status = attendee.responseStatus || "unknown";
    const attended = mentioned || status === "accepted";

    items.push({
      json: {
        attendeeName: displayName,
        attendeeEmail: email,
        attendeeRole: "Team Member",
        attended: attended,
        mentionedInMeeting: mentioned,
        calendarStatus: status,
        meetingTitle: fathomData.meetingTitle || "Meeting",
        meetingPurpose: fathomData.meetingPurpose || "Team discussion",
        keyTakeaways: fathomData.keyTakeaways || "See full meeting notes",
        actionItems: fathomData.actionItems || "Review meeting notes",
        nextSteps: fathomData.nextSteps || "Follow up on action items",
        organizerName: fathomData.organizerName || "Altix Codeit",
        organizerEmail: fathomData.organizerEmail || "priyanjana.codeit@gmail.com",
        companyName: fathomData.companyName || "Codeit"
      }
    });
  }

  // If items is empty, return default
  if (items.length === 0) {
    return [{
      json: {
        attendeeName: "Participant",
        attendeeEmail: "priyanjana2019@gmail.com",
        attended: false,
        mentionedInMeeting: false,
        debugInfo: `Found ${attendees.length} attendees but all were filtered out`
      }
    }];
  }

  return items;

} catch (error) {
  return [{
    json: {
      error: error.message,
      attendeeName: "Error: " + error.message,
      attendeeEmail: "error@company.com",
      debugInfo: error.toString()
    }
  }];
}

